    (EXTRACT(EPOCH FROM (MAX(received_at) - INTERVAL '3 days')) * 1000)::bigint,
    EXTRACT(EPOCH FROM TIMESTAMP '2022-07-01 00:00:00+00')::bigint * 1000
) AS watermark_ms
FROM core.tax_documents
WHERE source_type = 'GMAIL';

parameters.jsCode:
const items = $input.all();
const watermarkMs = items[0].json.watermark_ms;
const afterDate = new Date(watermarkMs);

const batchId = $items('Start Batch')[0].json.batch_id;

const fmt = (d) => d.getFullYear() + '/' + String(d.getMonth()+1).padStart(2,'0') + '/' + String(d.getDate()).padStart(2,'0');

const today = new Date();
const query = 'has:attachment filename:pdf after:' + fmt(afterDate) + ' before:' + fmt(today);

return [{ json: { query, batchId, afterDate: afterDate.toISOString(), beforeDate: today.toISOString() } }];

// runOnceForAllItems â€” avoids $json Proxy entirely.
let batchId = null;
try {
  const bqItems = $items('Build Gmail Query');
  if (bqItems && bqItems.length > 0) {
    const bqJson = JSON.parse(JSON.stringify(bqItems[0].json));
    batchId = bqJson.batchId !== undefined ? bqJson.batchId : null;
  }
} catch(e) { batchId = null; }

return $input.all().map(function(item) {
  const msg = JSON.parse(JSON.stringify(item.json));

  const msgId          = String(msg.id || '');
  const internalDateMs = parseInt(String(msg.internalDate || '0'), 10);
  const snippet        = String(msg.snippet || '');
  const mimeType       = String(msg.payload && msg.payload.mimeType ? msg.payload.mimeType : '');
  const subject        = String(msg.Subject || '');
  const from           = String(msg.From || '');
  const senderEmail    = from.includes('<')
    ? from.split('<')[1].replace('>', '').trim()
    : from;

  const hasAttachment  = true; // Gmail query guarantees has:attachment filename:pdf
  const stagingFilename = msgId + '_attachment.pdf';
  const stagingPath    = '/data/tax-collector/staging/' + stagingFilename;

  const metaJson = JSON.stringify({
    source_id: msgId,
    subject: subject,
    sender_email: senderEmail,
    received_at: new Date(internalDateMs).toISOString(),
    file_name: stagingFilename,
    file_ext: 'pdf',
    file_size_bytes: null
  });

  return {
    json: {
      id: msgId,
      threadId: String(msg.threadId || ''),
      internalDate: String(msg.internalDate || '0'),
      snippet: snippet,
      sizeEstimate: Number(msg.sizeEstimate || 0),
      Subject: subject,
      From: from,
      _tc: {
        hasAttachment: Boolean(hasAttachment),
        stagingPath: stagingPath,
        metaJson: metaJson,
        subject: subject,
        senderEmail: senderEmail,
        internalDateMs: Number(internalDateMs),
        batchId: batchId
      }
    }
  };
});

const items = $input.all();

function isPdfPart(p) {
  var mt = (p.mimeType || '').toLowerCase();
  var fn = (p.filename || '').toLowerCase();
  return mt.indexOf('pdf') !== -1 || fn.endsWith('.pdf');
}

function findPdfAttachments(parts) {
  var found = [];
  if (!parts || !Array.isArray(parts)) return found;
  for (var i = 0; i < parts.length; i++) {
    var p = parts[i];
    var hasContent = p.body && (p.body.attachmentId || (p.body.data && p.body.data.length > 0));
    if (isPdfPart(p) && hasContent) {
      found.push({
        attachmentId: p.body.attachmentId || null,
        inlineData: p.body.data || null,
        filename: p.filename || 'attachment.pdf',
        mimeType: p.mimeType || 'application/pdf'
      });
    }
    if (p.parts) {
      var nested = findPdfAttachments(p.parts);
      for (var j = 0; j < nested.length; j++) found.push(nested[j]);
    }
  }
  return found;
}

return items.map(function(item) {
  var msg = item.json;
  var messageId = String(msg.id || '');
  var parts = (msg.payload && msg.payload.parts) ? msg.payload.parts : [];
  var attachments = findPdfAttachments(parts);

  // Also check top-level payload itself
  if (attachments.length === 0 && msg.payload) {
    var p = msg.payload;
    var hasContent = p.body && (p.body.attachmentId || (p.body.data && p.body.data.length > 0));
    if (isPdfPart(p) && hasContent) {
      attachments = [{ attachmentId: p.body.attachmentId || null, inlineData: p.body.data || null, filename: p.filename || 'attachment.pdf', mimeType: p.mimeType || 'application/pdf' }];
    }
  }

  var first = attachments.length > 0 ? attachments[0] : null;
  var stagingPath = '/data/tax-collector/staging/' + messageId + '_attachment.pdf';
  var metaJson = '{}';
  var batchId = null;
  try {
    var tagItems = $items('Tag Messages');
    for (var k = 0; k < tagItems.length; k++) {
      var tj = JSON.parse(JSON.stringify(tagItems[k].json));
      if (tj.id === messageId) {
        if (tj._tc && tj._tc.stagingPath) stagingPath = tj._tc.stagingPath;
        if (tj._tc && tj._tc.metaJson) metaJson = tj._tc.metaJson;
        if (tj._tc && tj._tc.batchId != null) batchId = tj._tc.batchId;
        break;
      }
    }
  } catch(e) {}

  if (!first) {
    return { json: { messageId: messageId, stagingPath: stagingPath, metaJson: metaJson, batchId: batchId, _noAttachmentFound: true } };
  }
  return { json: { messageId: messageId, attachmentId: first.attachmentId, inlineData: first.inlineData, attachmentFilename: first.filename, attachmentMimeType: first.mimeType, stagingPath: stagingPath, metaJson: metaJson, batchId: batchId, _noAttachmentFound: false } };
});

var cmdItems = $input.all();

var batchId = null;
try {
  var bqItems = $items('Build Gmail Query');
  if (bqItems && bqItems.length > 0) {
    var bqJson = JSON.parse(JSON.stringify(bqItems[0].json));
    if (bqJson.batchId !== undefined) batchId = bqJson.batchId;
  }
} catch(e) {}

return cmdItems.map(function(item) {
  var raw = JSON.parse(JSON.stringify(item.json));
  var exitCode = raw.exitCode !== undefined ? Number(raw.exitCode) : 0;
  return {
    json: {
      exitCode: exitCode,
      _success: exitCode === 0,
      batchId: batchId,
      stdout: String(raw.stdout || ''),
      stderr: String(raw.stderr || '')
    }
  };
});

const bodyText = $json.snippet || '';

return [{
  json: {
    id: $json.id,
    threadId: $json.threadId || '',
    internalDate: $json.internalDate || '0',
    Subject: $json.Subject || '',
    From: $json.From || '',
    _tc: {
      ...$json._tc,
      bodyText: bodyText.substring(0, 4000)
    }
  }
}];

