const msg = $items("Extract Body Text")[$itemIndex].json;
const ollamaRaw = $json?.response || '{}';
let classification;
try {
  classification = JSON.parse(ollamaRaw);
} catch(e) {
  classification = { category: 'Invoice / Receipt — Other', fy_year: null, is_deductible: false, confidence: 0.0 };
}

const batchId = msg._tc?.batchId;
const today = new Date();
const fyYear = (classification.fy_year >= 2020 && classification.fy_year <= 2035)
  ? classification.fy_year
  : (today.getMonth() >= 6 ? today.getFullYear() + 1 : today.getFullYear());

// Escape single quotes for SQL template substitution
const esc = (s) => (s || '').replace(/'/g, "''");

return [{
  json: {
    source_type: 'GMAIL',
    source_id: msg.id,
    subject: esc(msg._tc?.subject),
    sender_email: esc(msg._tc?.senderEmail),
    received_at: new Date(msg._tc?.internalDateMs || Date.now()).toISOString(),
    file_name: null,
    file_ext: null,
    file_size_bytes: null,
    content_preview: esc((msg._tc?.bodyText || '').substring(0, 500)),
    raw_json: esc(JSON.stringify({ classification, body_text_length: (msg._tc?.bodyText || '').length })),
    batch_id: batchId
  }
}];

const allItems = $input.all();
const rowsExtracted = allItems.length;
let rowsLoaded = 0;
let rowsSkipped = 0;

allItems.forEach(item => {
  if (item.json.exitCode !== undefined) {
    if (item.json.exitCode === 0) rowsLoaded++; else rowsSkipped++;
  } else {
    rowsLoaded++;
  }
});

const batchId = $items("Build Gmail Query")[0]?.json?.batchId;
return [{ json: { batchId, rowsExtracted, rowsLoaded, rowsSkipped } }];

