SET status = 'SUCCESS', rows_extracted = {{ $json.rowsExtracted }}, rows_loaded = {{ $json.rowsLoaded }}, rows_skipped = {{ $json.rowsSkipped }}, completed_at = NOW()
WHERE batch_id = {{ $json.batchId }};

