const meta = $input.first().json;
return [{
  json: {
    stagingPath: meta.stagingPath,
    pdfData: meta.inlineData,
    metaEncoded: encodeURIComponent(meta.metaJson || "{}").replace(/'/g, "%27")
  }
}];

const nodeFs = require("fs");
const nodePath = require("path");
const pdfData = $json.pdfData;
const stagingPath = $json.stagingPath;
const metaEncoded = $json.metaEncoded;

if (!pdfData) {
  // No PDF data found for this email — skip silently
  return [];
}

// Convert base64url to buffer
const b64 = pdfData.replace(/-/g, "+").replace(/_/g, "/");
const padded = b64 + "=".repeat((4 - b64.length % 4) % 4);
const buf = Buffer.from(padded, "base64");

nodeFs.mkdirSync(nodePath.dirname(stagingPath), { recursive: true });
nodeFs.writeFileSync(stagingPath, buf);

return [{ json: { stagingPath, metaEncoded } }];

var item = $input.first().json;
